   681	parse_oct(const char* s, std::uint32_t& v)
   682	{
   683	  if (*s < '0' || *s > '9')
   684	    return nullptr;
   685	  std::uint32_t num = 0;
   686	  while ('0' <= *s && *s <= '9') {
   687	    num = num * 10 + (*s - '0');
   688	    ++s;
   689	  }
   690	  v = num;
   691	  return s;
